function (frameArray) {
  if (!Array.isArray(frameArray) || frameArray.length < 3) {
    return null;
  }

  var parsers = [
    {
      name: 'type 1',
      match: function (frame) {
        return frame[0] === 0x02 && frame[frame.length - 1] === 0x03 && (frame[1] === 0x2b || frame[1] === 0x2d);
      },
      parse: function (frame) {
        var digits = [];
        for (var i = 2; i < frame.length - 1; i += 1) {
          var ch = frame[i];
          if (ch >= 0x30 && ch <= 0x39) {
            digits.push(ch - 0x30);
          }
        }
        if (digits.length === 0) {
          return null;
        }
        var tail = digits.slice(-6);
        var value = 0;
        for (var j = 0; j < tail.length; j += 1) {
          value = value * 10 + tail[j];
        }
        if (frame[1] === 0x2d) {
          value = -value;
        }
        return value / 1000;
      }
    },
    {
      name: 'type 2',
      match: function (frame) {
        return frame[0] === 0x02 && frame[frame.length - 1] === 0x0d && (frame.length === 17 || frame.length === 18);
      },
      parse: function (frame) {
        var dotPos = frame[1] & 0x07;
        var powNum = 2 - dotPos;
        if (powNum > 0) {
          powNum = 0;
        }
        var raw = 0;
        for (var k = 0; k < 6; k += 1) {
          var b = frame[4 + k];
          var d = (b >= 0x30 && b <= 0x39) ? (b - 0x30) : 0;
          raw += d * Math.pow(10, 5 + powNum - k);
        }
        return raw / 1000;
      }
    }
  ];

  for (var p = 0; p < parsers.length; p += 1) {
    var parser = parsers[p];
    if (!parser.match(frameArray)) {
      continue;
    }
    var result = parser.parse(frameArray);
    if (result !== null && result !== undefined && !Number.isNaN(Number(result))) {
      return Number(result);
    }
  }

  return null;
}
